'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/context/AuthContext';
import { useTasks } from '@/context/TaskContext';
import { Task } from '@/types';
import ProtectedRoute from '@/components/ProtectedRoute';
import TaskCard from '@/components/TaskCard';
import TaskModal from '@/components/TaskModal';
import { LogOut, Plus, LayoutDashboard } from 'lucide-react';
import { motion } from 'framer-motion';

export default function Dashboard() {
  const { user, logout } = useAuth();
  const { tasks, loading, error, fetchTasks } = useTasks();
  
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<Task | null>(null);

  useEffect(() => {
    fetchTasks();
  }, [fetchTasks]);

  const handleCreateNew = () => {
    setEditingTask(null);
    setIsModalOpen(true);
  };

  const handleEdit = (task: Task) => {
    setEditingTask(task);
    setIsModalOpen(true);
  };

  const columns = {
    todo: tasks.filter((t) => t.status === 'todo'),
    'in-progress': tasks.filter((t) => t.status === 'in-progress'),
    done: tasks.filter((t) => t.status === 'done'),
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    show: {
      opacity: 1,
      transition: { staggerChildren: 0.1 }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    show: { opacity: 1, y: 0, transition: { type: 'spring', bounce: 0.4 } }
  };

  return (
    <ProtectedRoute>
      <div className="min-h-screen bg-transparent flex flex-col relative overflow-hidden bg-grid-pattern">
        {/* Decorative background blurs */}
        <div className="absolute top-[-15%] left-[-10%] w-[50%] h-[50%] bg-blue-400/20 rounded-full blur-[120px] pointer-events-none" />
        <div className="absolute bottom-[-15%] right-[-10%] w-[50%] h-[50%] bg-indigo-400/20 rounded-full blur-[120px] pointer-events-none" />

        <header className="bg-white/70 backdrop-blur-md border-b border-gray-200/50 sticky top-0 z-10 shadow-sm">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
            <div className="flex items-center space-x-3">
              <div className="p-2 bg-gradient-to-br from-blue-600 to-indigo-600 rounded-lg shadow-sm text-white">
                <LayoutDashboard size={20} />
              </div>
              <h1 className="text-2xl font-bold text-gray-900 tracking-tight">
                Team Board
              </h1>
            </div>
            <div className="flex items-center space-x-5">
              <span className="text-sm font-medium text-gray-500 hidden sm:inline-block">
                {user?.email}
              </span>
              <button
                onClick={logout}
                className="p-2 text-gray-500 hover:text-red-500 transition-colors flex items-center space-x-1.5 rounded-md hover:bg-red-50 font-medium text-sm"
              >
                <LogOut size={16} />
                <span className="hidden sm:inline-block">Logout</span>
              </button>
            </div>
          </div>
        </header>

        <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8 z-10">
          <div className="flex justify-between items-center mb-10">
            <div>
              <h2 className="text-2xl font-bold text-gray-900 tracking-tight">Your Tasks</h2>
              <p className="text-gray-500 mt-1 text-sm">Design, develop, and deploy.</p>
            </div>
            <motion.button
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={handleCreateNew}
              className="px-5 py-2.5 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white rounded-xl shadow-md transition-all text-sm font-semibold flex items-center"
            >
              <Plus size={18} className="mr-1.5" /> New Task
            </motion.button>
          </div>

          {error && (
            <div className="mb-6 p-4 bg-red-50 text-red-600 rounded-xl border border-red-200 text-sm font-medium shadow-sm">
              {error}
            </div>
          )}

          {loading && tasks.length === 0 ? (
            <div className="flex justify-center items-center h-[50vh]">
              <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-blue-600"></div>
            </div>
          ) : (
            <motion.div 
              variants={containerVariants}
              initial="hidden"
              animate="show"
              className="grid grid-cols-1 md:grid-cols-3 gap-6 items-start"
            >
              {/* To Do Column */}
              <motion.div variants={itemVariants} className="bg-gray-100/60 backdrop-blur-md p-5 rounded-2xl min-h-[600px] border border-gray-200/50 shadow-sm">
                <div className="flex items-center justify-between mb-5 px-1">
                  <h3 className="font-bold text-gray-700 uppercase tracking-widest text-xs flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-gray-400"></span>
                    To Do
                  </h3>
                  <span className="bg-white text-gray-600 px-2.5 py-1 rounded-full text-xs font-bold shadow-sm border border-gray-100">
                    {columns.todo.length}
                  </span>
                </div>
                <div className="space-y-4">
                  {columns.todo.map((task) => (
                    <TaskCard key={task._id} task={task} onEdit={handleEdit} />
                  ))}
                  {columns.todo.length === 0 && (
                    <div className="flex items-center justify-center p-6 text-sm text-gray-400 border-2 border-dashed border-gray-200 rounded-xl bg-white/30">
                      No tasks yet
                    </div>
                  )}
                </div>
              </motion.div>

              {/* In Progress Column */}
              <motion.div variants={itemVariants} className="bg-blue-50/50 backdrop-blur-md p-5 rounded-2xl min-h-[600px] border border-blue-100/50 shadow-sm">
                <div className="flex items-center justify-between mb-5 px-1">
                  <h3 className="font-bold text-blue-700 uppercase tracking-widest text-xs flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-blue-500"></span>
                    In Progress
                  </h3>
                  <span className="bg-white text-blue-800 px-2.5 py-1 rounded-full text-xs font-bold shadow-sm border border-blue-100">
                    {columns['in-progress'].length}
                  </span>
                </div>
                <div className="space-y-4">
                  {columns['in-progress'].map((task) => (
                    <TaskCard key={task._id} task={task} onEdit={handleEdit} />
                  ))}
                  {columns['in-progress'].length === 0 && (
                    <div className="flex items-center justify-center p-6 text-sm text-blue-300 border-2 border-dashed border-blue-200/60 rounded-xl bg-white/40">
                      Drop tasks here
                    </div>
                  )}
                </div>
              </motion.div>

              {/* Done Column */}
              <motion.div variants={itemVariants} className="bg-green-50/50 backdrop-blur-md p-5 rounded-2xl min-h-[600px] border border-green-100/50 shadow-sm">
                <div className="flex items-center justify-between mb-5 px-1">
                  <h3 className="font-bold text-green-700 uppercase tracking-widest text-xs flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-green-500"></span>
                    Done
                  </h3>
                  <span className="bg-white text-green-800 px-2.5 py-1 rounded-full text-xs font-bold shadow-sm border border-green-100">
                    {columns.done.length}
                  </span>
                </div>
                <div className="space-y-4">
                  {columns.done.map((task) => (
                    <TaskCard key={task._id} task={task} onEdit={handleEdit} />
                  ))}
                  {columns.done.length === 0 && (
                    <div className="flex items-center justify-center p-6 text-sm text-green-300 border-2 border-dashed border-green-200/60 rounded-xl bg-white/40">
                      Finish tasks to see them here
                    </div>
                  )}
                </div>
              </motion.div>
            </motion.div>
          )}
        </main>
      </div>

      <TaskModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        task={editingTask}
      />
    </ProtectedRoute>
  );
}
